const FAQ_ITEMS = [{"q": "来云顶班和BOSS直聘、58同城有什么区别？", "a": "BOSS直聘/58同城是信息平台，收割信息费后服务结束。来云顶班是「同城日结兼职交付基础设施」——介入用工全流程：GPS定位打卡、工资日结、人身保险、争议处理，用平台机制替代人工监督。"}, {"q": "商家如何入驻？", "a": "提交营业执照和个人身份证，通过实名认证后即可发布岗位。平台提供职位模板和参考定价建议，新商家入驻首月免收服务费。"}, {"q": "工资是怎么结算的？", "a": "工资日结——商家确认工作量后，平台即时结算到兼职人员账户，支持微信/支付宝。商家资金先托管在平台，出现争议时可申请平台仲裁。"}, {"q": "兼职过程中受伤怎么办？", "a": "平台为每位在岗兼职购买人身意外险。发生意外时，商家和兼职均可发起申诉，平台 24 小时内介入处理，严重情况启动保险理赔流程。"}, {"q": "GPA打卡是什么？有什么用？", "a": "GPA = 地理位置（Geo）+ 人脸（People）+ 打卡（Attendance）。兼职人员到岗时需 GPS定位 + 人脸识别确认在场，结合时间戳自动生成出勤记录，从根本上解决虚假打卡问题。"}, {"q": "平台盈利模式是什么？", "a": "三项收入：① 商家服务费（每单收取5%-10%）；② 保险分成（人身意外险）；③ 增值服务（批量招聘、高级数据分析、企业定制方案）。规模化后广告和增值收入潜力巨大。"}, {"q": "来云顶班对商家收费吗？", "a": "商家入驻免费；实际用工时按单结算，平台收取一定比例服务费（行业最低），详情见商户协议。"}, {"q": "兼职人员工资什么时候结算？", "a": "兼职人员工资次日结算（T+1），商家确认后自动打款，无需等待月度结算，解决传统平台拖延问题。"}, {"q": "来云顶班有保险吗？", "a": "平台为每位在岗兼职人员购买了人身意外险，保障工作期间的安全，让商家和兼职人员都安心。"}, {"q": "如何保证兼职人员的工作质量？", "a": "GPA智能打卡（实时定位+人脸识别）+商家评分体系+投诉仲裁机制，三重保障服务质量。"}, {"q": "商家可以管理多个门店吗？", "a": "可以。商户后台支持多门店管理，统一发布用工需求、统一结算、统一查看报表，适合连锁品牌。"}, {"q": "城市合伙人需要什么条件？", "a": "无需加盟费，但需要具备本地商业资源和运营能力。平台提供标准化SOP、CRM系统、培训支持和数据监控工具，你负责本地商家拓展和团队管理。"}, {"q": "城市合伙人怎么赚钱？", "a": "三项收益：① 城市订单分成（每笔交易按比例分成）；② 服务费差价（平台给予的结算差价）；③ 增值业务分成（批量招聘、定制方案等高毛利业务）。"}];

